   108→async function getCurrentDate(): Promise<string> {
   109→  try {
   110→    // Cross-platform date formatting using Intl API instead of Unix date command
   111→    const timezone = process.env.TIME_ZONE || 'America/Los_Angeles';
   112→    const now = new Date();
   113→
   114→    const formatter = new Intl.DateTimeFormat('en-US', {
   115→      timeZone: timezone,
   116→      year: 'numeric',
   117→      month: '2-digit',
   118→      day: '2-digit',
   119→      hour: '2-digit',
   120→      minute: '2-digit',
   121→      second: '2-digit',
   122→      timeZoneName: 'short',
   123→      hour12: false
   124→    });
   125→
   126→    // Format: YYYY-MM-DD HH:MM:SS TZ
   127→    const parts = formatter.formatToParts(now);
   128→    const year = parts.find(p => p.type === 'year')?.value || '';
   129→    const month = parts.find(p => p.type === 'month')?.value || '';
   130→    const day = parts.find(p => p.type === 'day')?.value || '';
   131→    const hour = parts.find(p => p.type === 'hour')?.value || '';
   132→    const minute = parts.find(p => p.type === 'minute')?.value || '';
   133→    const second = parts.find(p => p.type === 'second')?.value || '';
   134→    const tzName = parts.find(p => p.type === 'timeZoneName')?.value || '';
   135→
   136→    return `${year}-${month}-${day} ${hour}:${minute}:${second} ${tzName}`;
   137→  } catch (error) {
   138→    console.error('Failed to get current date:', error);
   139→    return new Date().toISOString();
   140→  }
   141→}
   142→
   143→interface Settings {
   144→  contextFiles?: string[];
   145→  [key: string]: unknown;
   146→}
   147→
   148→/**
   149→ * Load settings.json and return the settings object.
   150→ */
   151→function loadSettings(paiDir: string): Settings {
   152→  const settingsPath = join(paiDir, 'settings.json');
   153→  if (existsSync(settingsPath)) {
   154→    try {
   155→      return JSON.parse(readFileSync(settingsPath, 'utf-8'));
   156→    } catch (err) {
   157→      console.error(`⚠️ Failed to parse settings.json: ${err}`);
   158→    }
   159→  }
   160→  return {};
   161→}
   162→
   163→/**
   164→ * Load context files from settings.json contextFiles array.
   165→ * Falls back to hardcoded paths if array not defined.
   166→ */
   167→function loadContextFiles(paiDir: string, settings: Settings): string {
   168→  const defaultFiles = [
   169→    'skills/PAI/SKILL.md',
   170→    'skills/PAI/SYSTEM/AISTEERINGRULES.md',
   171→    'skills/PAI/USER/AISTEERINGRULES.md'
   172→  ];
   173→
   174→  const contextFiles = settings.contextFiles || defaultFiles;
   175→  let combinedContent = '';
   176→
   177→  for (const relativePath of contextFiles) {
   178→    const fullPath = join(paiDir, relativePath);
   179→    if (existsSync(fullPath)) {
   180→      const content = readFileSync(fullPath, 'utf-8');
   181→      if (combinedContent) combinedContent += '\n\n---\n\n';
   182→      combinedContent += content;
   183→      console.error(`✅ Loaded ${relativePath} (${content.length} chars)`);
   184→    } else {
   185→      console.error(`⚠️ Context file not found: ${relativePath}`);
   186→    }
   187→  }
   188→
   189→  return combinedContent;
   190→}
   191→
   192→interface ProgressFile {
   193→  project: string;
   194→  status: string;
   195→  updated: string;
   196→  objectives: string[];
   197→  next_steps: string[];
   198→  handoff_notes: string;
   199→}
   200→
   201→/**
   202→ * Load relationship context for session startup.
   203→ * Returns a lightweight summary of key opinions and recent notes.
   204→ */
   205→function loadRelationshipContext(paiDir: string): string | null {
   206→  const parts: string[] = [];
   207→
   208→  // Load high-confidence opinions (>0.85) from OPINIONS.md
   209→  const opinionsPath = join(paiDir, 'skills/PAI/USER/OPINIONS.md');
   210→  if (existsSync(opinionsPath)) {
   211→    try {
   212→      const content = readFileSync(opinionsPath, 'utf-8');
   213→      const highConfidence: string[] = [];
   214→
   215→      // Extract opinions with confidence >= 0.85
   216→      const opinionBlocks = content.split(/^### /gm).slice(1);
   217→      for (const block of opinionBlocks) {
   218→        const lines = block.split('\n');
   219→        const statement = lines[0]?.trim();
   220→        const confidenceMatch = block.match(/\*\*Confidence:\*\*\s*([\d.]+)/);
   221→        const confidence = confidenceMatch ? parseFloat(confidenceMatch[1]) : 0;
   222→
   223→        if (confidence >= 0.85 && statement) {
   224→          highConfidence.push(`• ${statement} (${(confidence * 100).toFixed(0)}%)`);
   225→        }
   226→      }
   227→
   228→      if (highConfidence.length > 0) {
   229→        parts.push('**Key Opinions (high confidence):**');
   230→        parts.push(highConfidence.slice(0, 6).join('\n'));
   231→      }
   232→    } catch (err) {
   233→      console.error(`⚠️ Failed to load opinions: ${err}`);
   234→    }
   235→  }
   236→
   237→  // Load recent relationship notes (today and yesterday)
   238→  const today = new Date();
   239→  const yesterday = new Date(today);
   240→  yesterday.setDate(yesterday.getDate() - 1);
   241→
   242→  const formatDate = (d: Date) => d.toISOString().split('T')[0];
   243→  const formatMonth = (d: Date) => d.toISOString().slice(0, 7);
   244→
   245→  const recentNotes: string[] = [];
   246→  for (const date of [today, yesterday]) {
   247→    const notePath = join(
   248→      paiDir,
   249→      'MEMORY/RELATIONSHIP',
   250→      formatMonth(date),
   251→      `${formatDate(date)}.md`
   252→    );
   253→    if (existsSync(notePath)) {
   254→      try {
   255→        const content = readFileSync(notePath, 'utf-8');
   256→        // Extract just the note lines (starting with -)
   257→        const notes = content
   258→          .split('\n')
   259→          .filter(line => line.trim().startsWith('- '))
   260→          .slice(0, 5); // Last 5 notes per day
   261→        if (notes.length > 0) {
   262→          recentNotes.push(`*${formatDate(date)}:*`);
   263→          recentNotes.push(...notes);
   264→        }
   265→      } catch {}
   266→    }
   267→  }
   268→
   269→  if (recentNotes.length > 0) {
   270→    if (parts.length > 0) parts.push('');
   271→    parts.push('**Recent Relationship Notes:**');
   272→    parts.push(recentNotes.join('\n'));
   273→  }
   274→
   275→  if (parts.length === 0) return null;
   276→
   277→  return `
   278→## Relationship Context
   279→
   280→${parts.join('\n')}
   281→
   282→*Full details: USER/OPINIONS.md, MEMORY/RELATIONSHIP/*
   283→`;
   284→}
   285→
   286→async function checkActiveProgress(paiDir: string): Promise<string | null> {
   287→  const progressDir = join(paiDir, 'MEMORY', 'STATE', 'progress');
   288→
   289→  if (!existsSync(progressDir)) {
   290→    return null;
   291→  }
   292→
   293→  try {
   294→    const files = readdirSync(progressDir).filter(f => f.endsWith('-progress.json'));
   295→
   296→    if (files.length === 0) {
   297→      return null;
   298→    }
   299→
   300→    const activeProjects: ProgressFile[] = [];
   301→
   302→    for (const file of files) {
   303→      try {
   304→        const content = readFileSync(join(progressDir, file), 'utf-8');
   305→        const progress = JSON.parse(content) as ProgressFile;
   306→        if (progress.status === 'active') {
   307→          activeProjects.push(progress);
   308→        }
   309→      } catch (e) {
   310→        // Skip malformed files
   311→      }
   312→    }
   313→
   314→    if (activeProjects.length === 0) {
   315→      return null;
   316→    }
   317→
   318→    // Build summary of active work
   319→    let summary = '\n📋 ACTIVE WORK (from previous sessions):\n';
   320→
   321→    for (const proj of activeProjects) {
   322→      summary += `\n🔵 ${proj.project}\n`;
   323→
   324→      if (proj.objectives && proj.objectives.length > 0) {
   325→        summary += '   Objectives:\n';
   326→        proj.objectives.forEach(o => summary += `   • ${o}\n`);
   327→      }
   328→
   329→      if (proj.handoff_notes) {
   330→        summary += `   Handoff: ${proj.handoff_notes}\n`;
   331→      }
   332→
   333→      if (proj.next_steps && proj.next_steps.length > 0) {
   334→        summary += '   Next steps:\n';
   335→        proj.next_steps.forEach(s => summary += `   → ${s}\n`);
   336→      }
   337→    }
   338→
   339→    summary += '\n💡 To resume: `bun run ~/.claude/skills/PAI/Tools/SessionProgress.ts resume <project>`\n';
   340→    summary += '💡 To complete: `bun run ~/.claude/skills/PAI/Tools/SessionProgress.ts complete <project>`\n';
   341→
   342→    return summary;
   343→  } catch (error) {
   344→    console.error('Error checking active progress:', error);
   345→    return null;
   346→  }
   347→}
   348→
   349→async function main() {
   350→  try {
   351→    // Check if this is a subagent session - if so, exit silently
   352→    const claudeProjectDir = process.env.CLAUDE_PROJECT_DIR || '';
   353→    const isSubagent = claudeProjectDir.includes('/.claude/Agents/') ||
   354→                      process.env.CLAUDE_AGENT_TYPE !== undefined;
   355→
   356→    if (isSubagent) {
   357→      // Subagent sessions don't need PAI context loading
   358→      console.error('🤖 Subagent session - skipping PAI context loading');
   359→      process.exit(0);
   360→    }
   361→
   362→    const paiDir = getPaiDir();
   363→
   364→    // CRITICAL: Reset tab title IMMEDIATELY at session start
   365→    // This prevents stale titles from previous sessions bleeding through
   366→    resetTabTitle(paiDir);
   367→
   368→    // Record session start time for notification timing
   369→    recordSessionStart();
   370→    console.error('⏱️ Session start time recorded for notification timing');
   371→
   372→    // Only rebuild SKILL.md if source components are newer than the output
   373→    // This saves ~200-500ms on most session starts
   374→    const skillMdPath = join(paiDir, 'skills/PAI/SKILL.md');
   375→    const componentsDir = join(paiDir, 'skills/PAI/Components');
   376→    let needsRebuild = false;
   377→
   378→    try {
   379→      const skillMdStat = existsSync(skillMdPath) ? require('fs').statSync(skillMdPath) : null;
   380→      if (!skillMdStat) {
   381→        needsRebuild = true;
   382→      } else {
   383→        // Check if any component is newer than SKILL.md
   384→        const checkDir = (dir: string): boolean => {
   385→          try {
   386→            for (const entry of readdirSync(dir, { withFileTypes: true })) {
   387→              const fullPath = join(dir, entry.name);
   388→              if (entry.isDirectory()) {
   389→                if (checkDir(fullPath)) return true;
   390→              } else {
   391→                const entryStat = require('fs').statSync(fullPath);
   392→                if (entryStat.mtimeMs > skillMdStat.mtimeMs) return true;
   393→              }
   394→            }
   395→          } catch {}
   396→          return false;
   397→        };
   398→        needsRebuild = checkDir(componentsDir);
   399→      }
   400→    } catch {
   401→      needsRebuild = true; // If we can't check, rebuild to be safe
   402→    }
   403→
   404→    if (needsRebuild) {
   405→      console.error('🔨 Rebuilding SKILL.md (components changed)...');
   406→      try {
   407→        // Cross-platform path to CreateDynamicCore script
   408→        const rebuildScript = join(paiDir, 'skills', 'PAI', 'Tools', 'CreateDynamicCore.ts');
   409→        execSync(`bun "${rebuildScript}"`, {
   410→          cwd: paiDir,
   411→          stdio: 'pipe',
   412→          timeout: 5000
   413→        });
   414→        console.error('✅ SKILL.md rebuilt from latest components');
   415→      } catch (err) {
   416→        console.error(`⚠️ Failed to rebuild SKILL.md: ${err}`);
   417→        console.error('⚠️ Continuing with existing SKILL.md...');
   418→      }
   419→    } else {
   420→      console.error('✅ SKILL.md up-to-date (skipped rebuild)');
   421→    }
   422→
   423→    console.error('📚 Reading PAI core context...');
   424→
   425→    // Load settings.json to get contextFiles array
   426→    const settings = loadSettings(paiDir);
   427→    console.error(`✅ Loaded settings.json`);
   428→
   429→    // Load all context files from settings.json array
   430→    const contextContent = loadContextFiles(paiDir, settings);
   431→
   432→    if (!contextContent) {
   433→      console.error('❌ No context files loaded');
   434→      process.exit(1);
   435→    }
   436→
   437→    // Get current date/time to prevent confusion about dates
   438→    const currentDate = await getCurrentDate();
   439→    console.error(`📅 Current Date: ${currentDate}`);
   440→
   441→    // Extract identity values from settings for injection into context
   442→    const PRINCIPAL_NAME = (settings as Record<string, unknown>).principal &&
   443→      typeof (settings as Record<string, unknown>).principal === 'object'
   444→        ? ((settings as Record<string, unknown>).principal as Record<string, unknown>).name || 'User'
   445→        : 'User';
   446→    const DA_NAME = (settings as Record<string, unknown>).daidentity &&
   447→      typeof (settings as Record<string, unknown>).daidentity === 'object'
   448→        ? ((settings as Record<string, unknown>).daidentity as Record<string, unknown>).name || 'PAI'
   449→        : 'PAI';
   450→
   451→    console.error(`👤 Principal: ${PRINCIPAL_NAME}, DA: ${DA_NAME}`);
   452→
   453→    // Load relationship context (lightweight summary)
   454→    const relationshipContext = loadRelationshipContext(paiDir);
   455→    if (relationshipContext) {
   456→      console.error('💕 Loaded relationship context');
   457→    }
   458→
   459→    const message = `<system-reminder>
   460→PAI CONTEXT (Auto-loaded at Session Start)
   461→
   462→📅 CURRENT DATE/TIME: ${currentDate}
   463→
   464→## ACTIVE IDENTITY (from settings.json) - CRITICAL
   465→
   466→**⚠️ MANDATORY IDENTITY RULES - OVERRIDE ALL OTHER CONTEXT ⚠️**
   467→
   468→The user's name is: **${PRINCIPAL_NAME}**
   469→The assistant's name is: **${DA_NAME}**
   470→
   471→- ALWAYS address the user as "${PRINCIPAL_NAME}" in greetings and responses
   472→- NEVER use hardcoded names, "the user", or any other name - ONLY "${PRINCIPAL_NAME}"
   473→- The "danielmiessler" in the repo URL is the AUTHOR, NOT the user
   474→- This instruction takes ABSOLUTE PRECEDENCE over any other context
   475→
   476→---
   477→
   478→${contextContent}
   479→${relationshipContext ? '\n---\n' + relationshipContext : ''}
   480→---
   481→
   482→This context is now active. Additional context loads dynamically as needed.
   483→</system-reminder>`;
   484→
   485→    // Write to stdout (will be captured by Claude Code)
   486→    console.log(message);
   487→
   488→    // Output success confirmation for Claude to acknowledge
   489→    console.log('\n✅ PAI Context successfully loaded...');
   490→
   491→    // Check for active progress files and display them
   492→    const activeProgress = await checkActiveProgress(paiDir);
   493→    if (activeProgress) {
   494→      console.log(activeProgress);
   495→      console.error('📋 Active work found from previous sessions');
   496→    }
   497→
   498→    console.error('✅ PAI context injected into session');
   499→    process.exit(0);
   500→  } catch (error) {
   501→    console.error('❌ Error in load-pai-context hook:', error);
   502→    process.exit(1);
   503→  }
   504→}
   505→
   506→main();
