     1→/**
     2→ * Cross-Platform Path Utilities
     3→ *
     4→ * Provides platform-aware path handling for Windows, macOS, and Linux.
     5→ * All hooks should import from this file instead of using process.env.HOME directly.
     6→ *
     7→ * ENHANCEMENTS:
     8→ * - Robust Windows detection with fallbacks
     9→ * - Detailed error messages for Windows users
    10→ * - Debug logging for troubleshooting
    11→ * - Graceful degradation when platform features aren't available
    12→ */
    13→
    14→import * as path from 'path';
    15→import * as os from 'os';
    16→
    17→export const PLATFORM = process.platform;
    18→
    19→// Platform detection helpers
    20→export const IS_WINDOWS = PLATFORM === 'win32';
    21→export const IS_MAC = PLATFORM === 'darwin';
    22→export const IS_LINUX = PLATFORM === 'linux';
    23→
    24→// Debug mode for troubleshooting platform issues
    25→const DEBUG = process.env.DEBUG_PLATFORM === 'true' || process.env.DEBUG_HOOKS === 'true';
    26→
    27→/**
    28→ * Log debug message if debug mode is enabled
    29→ */
    30→function debugLog(message: string, ...args: any[]): void {
    31→  if (DEBUG) {
    32→    console.error(`[platform-paths] ${message}`, ...args);
    33→  }
    34→}
    35→
    36→/**
    37→ * Get the home directory in a cross-platform way with robust error handling.
    38→ *
    39→ * Windows: USERPROFILE environment variable
    40→ * macOS/Linux: HOME environment variable
    41→ *
    42→ * FALLBACKS:
    43→ * - Windows: Falls back to os.homedir() if USERPROFILE not set
    44→ * - All platforms: Falls back to current working directory if all else fails
    45→ */
    46→export const HOME_DIR = ((): string => {
    47→  try {
    48→    let homeDir: string;
    49→
    50→    if (IS_WINDOWS) {
    51→      // Windows: Try USERPROFILE first, then os.homedir()
    52→      homeDir = process.env.USERPROFILE || os.homedir();
    53→
    54→      if (!homeDir) {
    55→        const error = new Error(
    56→          'Could not determine home directory on Windows.\n' +
    57→          'Tried: %USERPROFILE% environment variable and os.homedir()\n' +
    58→          'Please ensure at least one of these is set.\n' +
    59→          'Current directory will be used as fallback.'
    60→        );
    61→        debugLog('WARNING: Could not determine HOME_DIR', error.message);
    62→        console.error(`[platform-paths] ${error.message}`);
    63→
    64→        // Fallback to current directory
    65→        homeDir = process.cwd() || 'C:\\';
    66→      }
    67→
    68→      debugLog(`Windows HOME_DIR detected: ${homeDir}`);
    69→      return homeDir;
    70→    } else {
    71→      // Unix (macOS/Linux): Try HOME first, then os.homedir()
    72→      homeDir = process.env.HOME || os.homedir();
    73→
    74→      if (!homeDir) {
    75→        const error = new Error(
    76→          'Could not determine home directory on Unix system.\n' +
    77→          'Tried: $HOME environment variable and os.homedir()\n' +
    78→          'Please ensure at least one of these is set.'
    79→        );
    80→        debugLog('WARNING: Could not determine HOME_DIR', error.message);
    81→        console.error(`[platform-paths] ${error.message}`);
    82→
    83→        // Fallback to current directory
    84→        homeDir = process.cwd() || '/tmp';
    85→      }
    86→
    87→      debugLog(`Unix HOME_DIR detected: ${homeDir}`);
    88→      return homeDir;
    89→    }
    90→  } catch (error) {
    91→    const fallback = IS_WINDOWS ? 'C:\\' : '/tmp';
    92→    console.error(`[platform-paths] CRITICAL: Failed to detect home directory:`, error);
    93→    console.error(`[platform-paths] Using fallback: ${fallback}`);
    94→    return fallback;
    95→  }
    96→})();
    97→
    98→/**
    99→ * Get the PAI directory (root of the Claude/PAI system) with validation.
   100→ * Uses PAI_DIR env var if set, otherwise defaults to ~/.claude
   101→ *
   102→ * WINDOWS NOTE: On Windows, this will typically be:
   103→ * - C:\Users\<Username>\.claude
   104→ *
   105→ * Error messages guide Windows users to correct location if issues occur.
   106→ */
   107→export const PAI_DIR = ((): string => {
   108→  try {
   109→    const envPaiDir = process.env.PAI_DIR;
   110→
   111→    if (envPaiDir) {
   112→      debugLog(`Using PAI_DIR from environment: ${envPaiDir}`);
   113→
   114→      // Validate that the path exists (if not, we'll create it later)
   115→      // Just normalize the path for now
   116→      const normalized = path.normalize(envPaiDir);
   117→
   118→      if (IS_WINDOWS && !normalized.match(/^[A-Za-z]:\\/)) {
   119→        // Warn if Windows path looks invalid (doesn't start with drive letter)
   120→        console.error(
   121→          `[platform-paths] WARNING: PAI_DIR path may be invalid on Windows: ${normalized}\n` +
   122→          `Expected format: C:\\Users\\YourName\\.claude\n` +
   123→          `Current value: ${envPaiDir}`
   124→        );
   125→      }
   126→
   127→      return normalized;
   128→    }
   129→
   130→    const defaultPaiDir = path.join(HOME_DIR, '.claude');
   131→    debugLog(`Using default PAI_DIR: ${defaultPaiDir}`);
   132→
   133→    return defaultPaiDir;
   134→  } catch (error) {
   135→    const fallback = path.join(HOME_DIR, '.claude');
   136→    console.error(`[platform-paths] ERROR: Failed to resolve PAI_DIR:`, error);
   137→    console.error(`[platform-paths] Using fallback: ${fallback}`);
   138→    return fallback;
   139→  }
   140→})();
   141→
   142→/**
   143→ * Get the Claude directory (alias for PAI_DIR for compatibility)
   144→ */
   145→export const CLAUDE_DIR = PAI_DIR;
   146→
   147→/**
   148→ * Platform-specific path separator
   149→ */
   150→export const PATH_SEPARATOR = path.sep;
   151→
   152→/**
   153→ * Join path segments using the platform-appropriate separator
   154→ */
   155→export function joinPath(...segments: string[]): string {
   156→  return path.join(...segments);
   157→}
   158→
   159→/**
   160→ * Normalize a path to use the platform-appropriate separator
   161→ * Converts forward slashes to backslashes on Windows
   162→ */
   163→export function normalizePath(filePath: string): string {
   164→  return path.normalize(filePath.replace(/\//g, path.sep));
   165→}
