   167→/**
   168→ * Get the temp directory in a cross-platform way with Windows-specific fallbacks.
   169→ *
   170→ * Windows: Checks %TEMP%, %TMP%, then os.tmpdir()
   171→ * macOS/Linux: Uses os.tmpdir() (typically /tmp)
   172→ *
   173→ * WINDOWS TEMP LOCATIONS (in order of preference):
   174→ * - %TEMP% (user temp, typically C:\Users\<Username>\AppData\Local\Temp)
   175→ * - %TMP% (fallback temp variable)
   176→ * - os.tmpdir() (Node.js default)
   177→ *
   178→ * Error messages help Windows users troubleshoot temp directory issues.
   179→ */
   180→export const TEMP_DIR = ((): string => {
   181→  try {
   182→    if (IS_WINDOWS) {
   183→      // Windows: Check TEMP, then TMP, then os.tmpdir()
   184→      const tempDir = process.env.TEMP || process.env.TMP || os.tmpdir();
   185→
   186→      if (!tempDir) {
   187→        const error = new Error(
   188→          'Could not determine temp directory on Windows.\n' +
   189→          'Tried: %TEMP%, %TMP%, and os.tmpdir()\n' +
   190→          'Please set %TEMP% environment variable.\n' +
   191→          `Using fallback: C:\\Windows\\Temp`
   192→        );
   193→        debugLog('WARNING: Could not determine TEMP_DIR', error.message);
   194→        console.error(`[platform-paths] ${error.message}`);
   195→
   196→        return 'C:\\Windows\\Temp';
   197→      }
   198→
   199→      debugLog(`Windows TEMP_DIR: ${tempDir}`);
   200→
   201→      // Validate temp directory is accessible (basic check)
   202→      const fs = require('fs');
   203→      try {
   204→        fs.accessSync(tempDir, fs.constants.W_OK);
   205→      } catch (accessError) {
   206→        console.error(
   207→          `[platform-paths] WARNING: Temp directory not writable: ${tempDir}\n` +
   208→          `This may cause issues with file operations.\n` +
   209→          `Error: ${accessError}`
   210→        );
   211→      }
   212→
   213→      return tempDir;
   214→    } else {
   215→      // Unix: Use os.tmpdir()
   216→      const tempDir = os.tmpdir();
   217→      debugLog(`Unix TEMP_DIR: ${tempDir}`);
   218→      return tempDir;
   219→    }
   220→  } catch (error) {
   221→    const fallback = IS_WINDOWS ? 'C:\\Windows\\Temp' : '/tmp';
   222→    console.error(`[platform-paths] CRITICAL: Failed to detect temp directory:`, error);
   223→    console.error(`[platform-paths] Using fallback: ${fallback}`);
   224→    return fallback;
   225→  }
   226→})();
   227→
   228→/**
   229→ * Get the session start file path for timing with platform-specific paths.
   230→ *
   231→ * Windows: %TEMP%\pai-session-start.txt (e.g., C:\Users\<Username>\AppData\Local\Temp\pai-session-start.txt)
   232→ * macOS/Linux: /tmp/pai-session-start.txt
   233→ *
   234→ * This file stores the session start timestamp for calculating task duration.
   235→ */
   236→export const SESSION_START_FILE = ((): string => {
   237→  try {
   238→    const sessionFile = IS_WINDOWS
   239→      ? path.join(TEMP_DIR, 'pai-session-start.txt')
   240→      : '/tmp/pai-session-start.txt';
   241→
   242→    debugLog(`SESSION_START_FILE: ${sessionFile}`);
   243→    return sessionFile;
   244→  } catch (error) {
   245→    console.error(`[platform-paths] ERROR: Failed to create session file path:`, error);
   246→
   247→    // Emergency fallback
   248→    if (IS_WINDOWS) {
   249→      return path.join(HOME_DIR, 'pai-session-start.txt');
   250→    } else {
   251→      return '/tmp/pai-session-start.txt';
   252→    }
   253→  }
   254→})();
