   256→// ============================================================================
   257→// WINDOWS-SPECIFIC HELPERS
   258→// ============================================================================
   259→
   260→/**
   261→ * Check if running under Windows Subsystem for Linux (WSL).
   262→ * Returns true if WSL is detected, false otherwise.
   263→ *
   264→ * This helps provide better error messages and feature detection.
   265→ */
   266→export function isWSL(): boolean {
   267→  if (!IS_LINUX) return false;
   268→
   269→  try {
   270→    const fs = require('fs');
   271→    const procVersion = fs.readFileSync('/proc/version', 'utf-8');
   272→    return procVersion.toLowerCase().includes('microsoft');
   273→  } catch {
   274→    return false;
   275→  }
   276→}
   277→
   278→/**
   279→ * Get a user-friendly platform name for error messages.
   280→ * Returns "Windows", "macOS", "Linux", or "Linux (WSL)" for better user guidance.
   281→ */
   282→export function getPlatformName(): string {
   283→  if (IS_WINDOWS) return 'Windows';
   284→  if (IS_MAC) return 'macOS';
   285→  if (IS_LINUX && isWSL()) return 'Linux (WSL)';
   286→  if (IS_LINUX) return 'Linux';
   287→  return PLATFORM;
   288→}
