   290→/**
   291→ * Validate that a path is accessible and writable.
   292→ * Returns true if valid, false otherwise.
   293→ *
   294→ * On Windows, also checks for long path issues (>260 characters).
   295→ */
   296→export function validatePathAccessible(filePath: string): { valid: boolean; error?: string } {
   297→  try {
   298→    const fs = require('fs');
   299→
   300→    // Check if path exists
   301→    if (!fs.existsSync(filePath)) {
   302→      return {
   303→        valid: false,
   304→        error: `Path does not exist: ${filePath}`
   305→      };
   306→    }
   307→
   308→    // Check write access
   309→    fs.accessSync(filePath, fs.constants.W_OK);
   310→
   311→    // Windows-specific: Check path length
   312→    if (IS_WINDOWS && filePath.length > 260) {
   313→      return {
   314→        valid: false,
   315→        error: `Path exceeds Windows MAX_PATH limit (260 characters): ${filePath}\n` +
   316→               `Length: ${filePath.length} characters\n` +
   317→               `Solution: Enable long path support or use shorter paths.`
   318→      };
   319→    }
   320→
   321→    return { valid: true };
   322→  } catch (error) {
   323→    return {
   324→      valid: false,
   325→      error: `Path not accessible: ${filePath}\nError: ${error.message}`
   326→    };
   327→  }
   328→}
