   330→/**
   331→ * Get Windows-specific environment diagnostic information.
   332→ * Useful for troubleshooting Windows setup issues.
   333→ */
   334→export function getWindowsDiagnostics(): Record<string, string> | null {
   335→  if (!IS_WINDOWS) return null;
   336→
   337→  try {
