   322→/**
   323→ * Emit failure event
   324→ * Call when capturing any failure condition
   325→ */
   326→export function emitFailure(
   327→  phase: AlgorithmPhase,
   328→  error: string,
   329→  context?: Record<string, any>
   330→): void {
   331→  emit({
   332→    type: 'failure',
   333→    phase,
   334→    data: {
   335→      error,
   336→      ...(context && { context })
   337→    }
   338→  });
   339→}
