   341→/**
   342→ * Emit loopback event
   343→ * Call when algorithm loops back to earlier phase
   344→ */
   345→export function emitLoopback(
   346→  from: AlgorithmPhase,
   347→  to: AlgorithmPhase,
   348→  reason: string
   349→): void {
   350→  emit({
   351→    type: 'loopback',
   352→    data: { from, to, reason }
   353→  });
   354→}
   355→
   356→/**
   357→ * Emit user_signal event
   358→ * Call when capturing user feedback or interruption
   359→ */
   360→export function emitUserSignal(
   361→  signalType: string,
   362→  content: any
   363→): void {
   364→  emit({
   365→    type: 'user_signal',
   366→    data: {
   367→      type: signalType,
   368→      content: typeof content === 'string'
   369→        ? content.slice(0, MAX_PREVIEW_LENGTH)
   370→        : content
   371→    }
   372→  });
   373→}
   374→
   375→/**
   376→ * Higher-order function to wrap a hook with trace instrumentation
   377→ * Automatically emits hook_start and hook_end events
   378→ */
   379→export function withTracing<T>(
   380→  hookName: string,
   381→  trigger: string,
   382→  fn: () => Promise<T>
   383→): Promise<T> {
   384→  const startTime = Date.now();
   385→  emitHookStart(hookName, trigger);
   386→
   387→  return fn()
   388→    .finally(() => {
   389→      emitHookEnd(hookName, Date.now() - startTime);
   390→    });
   391→}
