     9→
    10→export type AlgorithmPhase = 'OBSERVE' | 'THINK' | 'PLAN' | 'BUILD' | 'EXECUTE' | 'VERIFY' | 'LEARN';
    11→
    12→// Cross-platform path resolution using getPaiDir from paths.ts
    13→const WORK_DIR = join(getPaiDir(), 'MEMORY', 'WORK');
    14→
    15→/**
    16→ * Find the most recent active work directory
    17→ */
    18→export function findActiveWorkDir(): string | null {
    19→  try {
    20→    if (!existsSync(WORK_DIR)) return null;
    21→
    22→    const entries = readdirSync(WORK_DIR, { withFileTypes: true })
    23→      .filter(d => d.isDirectory() && d.name !== 'Signals')
    24→      .map(d => ({ name: d.name, path: join(WORK_DIR, d.name) }))
    25→      .sort((a, b) => b.name.localeCompare(a.name));
    26→
    27→    if (entries.length === 0) return null;
    28→
    29→    // Return most recent that isn't completed
    30→    for (const entry of entries) {
    31→      // Check session META.yaml for status
    32→      const metaPath = join(entry.path, 'META.yaml');
    33→      if (existsSync(metaPath)) {
    34→        const content = readFileSync(metaPath, 'utf-8');
    35→        if (!content.includes('status: "COMPLETED"')) {
    36→          return entry.path;
    37→        }
    38→      } else {
    39→        // No META.yaml means session is likely active (new format)
    40→        const tasksDir = join(entry.path, 'tasks');
    41→        if (existsSync(tasksDir)) {
    42→          return entry.path;
    43→        }
    44→      }
    45→    }
    46→
    47→    // Fallback to most recent
    48→    return entries[0].path;
    49→  } catch {
    50→    return null;
    51→  }
    52→}
