     1→#!/usr/bin/env bun
     2→/**
     3→ * RebuildSkill.ts - Auto-rebuild CORE SKILL.md from Components
     4→ *
     5→ * PURPOSE:
     6→ * Automatically rebuilds SKILL.md from Components/ after every response.
     7→ * Ensures SKILL.md stays current if components were edited during the session.
     8→ *
     9→ * TRIGGER: Stop event (via StopOrchestrator)
    10→ *
    11→ * BEHAVIOR:
    12→ * - Checks if any Component file is newer than SKILL.md
    13→ * - If yes, runs BuildSkill.ts to regenerate SKILL.md
    14→ * - Logs rebuild status to stderr
    15→ *
    16→ * DESIGN RATIONALE:
    17→ * - Rebuild on session END (not START) keeps LoadContext fast
    18→ * - Components are source of truth, SKILL.md is generated artifact
    19→ * - No manual `bun BuildSkill.ts` needed - happens automatically
    20→ */
    21→
    22→import { statSync, readdirSync } from 'fs';
    23→import { join } from 'path';
    24→import { spawnSync } from 'child_process';
    25→import { PLATFORM } from '../lib/platform-paths';
    26→import { getPaiDir } from '../lib/paths';
    27→
    28→export async function handleRebuildSkill(): Promise<void> {
    29→  const PAI_DIR = getPaiDir();
    30→  const CORE_DIR = join(PAI_DIR, 'skills', 'PAI');
    31→  const COMPONENTS_DIR = join(CORE_DIR, 'Components');
    32→  const SKILL_MD = join(CORE_DIR, 'SKILL.md');
    33→  const BUILD_SCRIPT = join(CORE_DIR, 'Tools/CreateDynamicCore.ts');
    34→
    35→  try {
    36→    // Check if SKILL.md exists
    37→    let skillStat;
    38→    try {
    39→      skillStat = statSync(SKILL_MD);
    40→    } catch {
    41→      // SKILL.md doesn't exist - rebuild needed
    42→      console.error('[RebuildSkill] SKILL.md missing - rebuilding');
    43→      rebuild(BUILD_SCRIPT);
    44→      return;
    45→    }
    46→
    47→    // Check if any component is newer than SKILL.md
    48→    const components = readdirSync(COMPONENTS_DIR).filter(f => f.endsWith('.md'));
    49→    const anyNewer = components.some(file => {
    50→      const componentPath = join(COMPONENTS_DIR, file);
    51→      const componentStat = statSync(componentPath);
    52→      return componentStat.mtimeMs > skillStat.mtimeMs;
    53→    });
    54→
    55→    if (anyNewer) {
    56→      console.error('[RebuildSkill] Components modified - rebuilding SKILL.md');
    57→      rebuild(BUILD_SCRIPT);
    58→    } else {
    59→      console.error('[RebuildSkill] SKILL.md is current - no rebuild needed');
    60→    }
    61→  } catch (error) {
    62→    console.error('[RebuildSkill] Error checking/rebuilding:', error);
    63→  }
    64→}
    65→
    66→function rebuild(buildScript: string): void {
    67→  const PAI_DIR = getPaiDir();
    68→  const result = spawnSync('bun', [buildScript], {
    69→    cwd: join(PAI_DIR, 'skills', 'PAI'),
    70→    encoding: 'utf-8',
    71→    shell: PLATFORM === 'win32', // Windows requires shell for some commands
    72→  });
    73→
    74→  if (result.error) {
    75→    console.error('[RebuildSkill] Build failed:', result.error);
    76→  } else {
    77→    console.error('[RebuildSkill]', result.stdout?.trim() || 'Build completed');
    78→  }
    79→}
