   264→/**
   265→ * Set terminal tab title and color based on state
   266→ * Cross-platform support: Windows Terminal, Kitty, and other terminals
   267→ */
   268→function setTabTitle(title: string, state: TabState = 'normal'): void {
   269→  try {
   270→    // Add "…" suffix for active states
   271→    const titleWithSuffix = state !== 'normal' ? `${title}…` : title;
   272→    const truncated = titleWithSuffix.length > 50 ? titleWithSuffix.slice(0, 47) + '…' : titleWithSuffix;
   273→
   274→    // Platform detection with better error handling
   275→    const isWindows = process.platform === 'win32';
   276→    const isKitty = process.env.TERM === 'xterm-kitty' || process.env.KITTY_LISTEN_ON;
   277→
   278→    if (isWindows) {
   279→      // Windows Terminal / ConHost escape sequence
   280→      // Using OSC 0 (set window title) and OSC 2 (set icon title)
   281→      // Note: Tab colors don't work on Windows Terminal - only title
   282→      try {
   283→        const osc = `\x1b]0;${truncated}\x07`;
   284→        process.stdout.write(osc);
   285→        console.error(`[UpdateTabTitle] Set title via Windows Terminal escape sequence: "${truncated}"`);
   286→      } catch (writeError) {
   287→        console.error(`[UpdateTabTitle] WARNING: Failed to write to stdout on Windows:`, writeError);
   288→        console.error(`[UpdateTabTitle] This is expected in non-terminal environments (e.g., GUI apps)`);
   289→      }
   290→    } else if (isKitty) {
   291→      // Use Kitty remote control - works even without TTY
   292→      const escaped = truncated.replace(/'/g, "'\\''");
   293→      execSync(`kitty @ set-tab-title "${escaped}"`, { stdio: 'ignore', timeout: 2000 });
   294→
   295→      // Set color based on state
   296→      if (state === 'inference') {
   297→        // Purple for inference/AI thinking - active tab stays dark blue, inactive shows purple
   298→        execSync(
   299→          `kitten @ set-tab-color --self active_bg=${ACTIVE_TAB_BG} active_fg=${ACTIVE_TEXT} inactive_bg=${TAB_INFERENCE_BG} inactive_fg=${INACTIVE_TEXT}`,
   300→          { stdio: 'ignore', timeout: 2000 }
   301→        );
   302→        console.error('[UpdateTabTitle] Set inference color (purple on inactive only)');
   303→      } else if (state === 'working') {
   304→        // Orange for actively working - active tab stays dark blue, inactive shows orange
   305→        execSync(
   306→          `kitten @ set-tab-color --self active_bg=${ACTIVE_TAB_BG} active_fg=${ACTIVE_TEXT} inactive_bg=${TAB_WORKING_BG} inactive_fg=${INACTIVE_TEXT}`,
   307→          { stdio: 'ignore', timeout: 2000 }
   308→        );
   309→        console.error('[UpdateTabTitle] Set working color (orange on inactive only)');
   310→      }
   311→
   312→      console.error('[UpdateTabTitle] Set via Kitty remote control');
   313→    } else {
   314→      // Fallback to escape codes for other terminals (Unix xterm/iTerm2, Windows Terminal fallback)
   315→      // Direct stdout write works on all platforms - no shell commands needed
   316→      try {
   317→        const osc = `\x1b]0;${truncated}\x07`;
   318→        process.stdout.write(osc);
   319→        console.error('[UpdateTabTitle] Set title via escape sequence fallback');
   320→      } catch (writeError) {
   321→        // Silent failure - stdout may not be available in all environments
   322→        if (process.env.DEBUG_HOOKS === 'true') {
   323→          console.error(`[UpdateTabTitle] Failed to set title:`, writeError);
   324→        }
   325→      }
   326→    }
   327→  } catch (err) {
   328→    // Non-blocking error - tab title updates are cosmetic
   329→    console.error(`[UpdateTabTitle] Failed to set tab title: ${err}`);
   330→    console.error(`[UpdateTabTitle] This is non-critical - continuing without tab title update`);
   331→  }
   332→}
