   343→  const message = summary.charAt(0).toUpperCase() + summary.slice(1);
   344→
   345→  const voiceId = identity.voiceId || 's3TPKV1kjDlVtZbl4Ksh';
   346→  const voiceSettings = identity.voice;
   347→
   348→  try {
   349→    const response = await fetch('http://localhost:8888/notify', {
   350→      method: 'POST',
   351→      headers: { 'Content-Type': 'application/json' },
   352→      body: JSON.stringify({
   353→        message: message,
   354→        title: `${identity.name} says`,
   355→        voice_enabled: true,
   356→        voice_id: voiceId,
   357→        voice_settings: voiceSettings ? {
   358→          stability: voiceSettings.stability ?? 0.5,
   359→          similarity_boost: voiceSettings.similarity_boost ?? 0.75,
   360→          style: voiceSettings.style ?? 0.0,
   361→          speed: voiceSettings.speed ?? 1.0,
   362→          use_speaker_boost: voiceSettings.use_speaker_boost ?? true,
   363→        } : undefined,
